package com.oneil.wellness.walkplanner.activity;import java.time.OffsetDateTime;import java.util.*;import org.springframework.data.jpa.repository.JpaRepository;public interface WalkActivityRepository extends JpaRepository<WalkActivity,UUID>{Optional<WalkActivity> findFirstByActivityStatus(ActivityStatus status);List<WalkActivity> findAllByOrderByOpportunityStartDesc();List<WalkActivity> findByOpportunityStartBetweenOrderByOpportunityStartAsc(OffsetDateTime start,OffsetDateTime end);List<WalkActivity> findByOpportunityStartAndOpportunityEnd(OffsetDateTime start,OffsetDateTime end);List<WalkActivity> findTop500ByOpportunityStartBeforeOrderByOpportunityStartAsc(OffsetDateTime cutoff);}
